def _filter_kwargs_for_instruction(instruction_id: str, kwargs: dict) -> dict:
    cls = instructions_registry.INSTRUCTION_DICT[instruction_id]
    sig = inspect.signature(cls.build_description)
    valid = set(sig.parameters.keys()) - {"self"}
    return {k: v for k, v in kwargs.items() if k in valid and v is not None}

def _extract_code(response: str, entry_point: str) -> str | None:
    # Strip prose prefix
    m = re.search(r'(?:Here|Sure|Okay|The|This|Below)', response)
    if m:
        response = response[m.start():]
    # Try markdown code block
    m = re.search(r'```(?:python)?\s*\n(.*?)```', response, re.DOTALL)
    if m:
        return m.group(1).strip()
    # Fallback: find def <entry_point>
    pattern = rf'def\s+{re.escape(entry_point)}\s*\('
    m = re.search(pattern, response)
    if m:
        return response[m.start():].strip()
    return response.strip()

def chat(
    client: OpenAI,
    model: str,
    messages: Iterable[dict],
    max_tokens: int = 2048,
    temperature: float = 0.0,
    no_think: bool = False,
    think_off: bool = False,
    **kwargs,
):
    msgs = list(messages)
    if msgs and msgs[-1].get("role") == "user":
        content = msgs[-1].get("content", "")
        if think_off and "<|think_off|>" not in content:
            msgs[-1] = {**msgs[-1], "content": f"<|think_off|>\n{content}"}
        if no_think and "/no_think" not in content and "<|think_off|>" not in content:
            sep = "" if content.endswith((" ", "\n", "\t")) else " "
            msgs[-1] = {**msgs[-1], "content": f"{content}{sep}/no_think"}
    return client.chat.completions.create(
        model=model,
        messages=msgs,
        max_tokens=max_tokens,
        temperature=temperature,
        **kwargs,
    )

def _compute_bleu(reference: str, candidate: str) -> float:
    try:
        from nltk.translate.bleu_score import sentence_bleu, SmoothingFunction
        return sentence_bleu([reference.split()], candidate.split(),
                             smoothing_function=SmoothingFunction().method1)
    except Exception:
        return 0.0
